/**
 * Tests para server.ts - Aumentar coverage de signal handlers y error handlers
 * @jest-environment node
 */

import { EventEmitter } from 'events';

// Mock de AppLogger antes de importar
jest.mock('../config/logger', () => ({
    AppLogger: {
        info: jest.fn(),
        warn: jest.fn(),
        error: jest.fn(),
        debug: jest.fn(),
    },
}));

// Mock de initializeApp
const mockListen = jest.fn();
const mockClose = jest.fn();
const mockApp = {
    listen: mockListen,
};

jest.mock('../app', () => ({
    initializeApp: jest.fn().mockResolvedValue(mockApp),
}));

// Mock de environment
jest.mock('../config/environment', () => ({
    getEnvironment: jest.fn().mockReturnValue({
        BACKEND_PORT: 4800,
        FRONTEND_URLS: 'http://localhost:3000',
        FRONTEND_URL: 'http://localhost:3000',
        NODE_ENV: 'test',
    }),
}));

describe('server.ts - Signal Handlers and Error Handlers', () => {
    let processEmitter: EventEmitter;
    let originalExit: any;
    let originalOn: any;
    let exitSpy: jest.SpyInstance;
    let signalHandlers: Map<string, Function>;

    beforeEach(() => {
        jest.clearAllMocks();
        signalHandlers = new Map();

        // Spy on process.exit
        originalExit = process.exit;
        exitSpy = jest.spyOn(process, 'exit').mockImplementation((code?: number) => {
            throw new Error(`process.exit(${code})`);
        });

        // Capture signal handlers
        originalOn = process.on;
        jest.spyOn(process, 'on').mockImplementation((event: string, handler: any) => {
            signalHandlers.set(event, handler);
            return process;
        });

        // Mock server.close to call callback
        mockClose.mockImplementation((callback: Function) => {
            if (callback) callback();
        });

        // Mock listen to return server with close method
        mockListen.mockImplementation((port: number, callback: Function) => {
            if (callback) callback();
            return { close: mockClose };
        });
    });

    afterEach(() => {
        process.exit = originalExit;
        process.on = originalOn;
        exitSpy.mockRestore();
        // Clear module cache to reset require.main
        jest.resetModules();
    });

    it('should register SIGINT handler and exit gracefully', async () => {
        // Import server to register handlers
        await import('../server');
        const { startServer } = await import('../server');

        // Start server
        await startServer();

        // Get SIGINT handler
        const sigintHandler = signalHandlers.get('SIGINT');
        expect(sigintHandler).toBeDefined();

        // Trigger SIGINT
        try {
            sigintHandler!();
            await new Promise(resolve => setTimeout(resolve, 10));
        } catch (error: any) {
            expect(error.message).toContain('process.exit(0)');
        }

        expect(mockClose).toHaveBeenCalled();
    });

    it('should register SIGTERM handler and exit gracefully', async () => {
        const { startServer } = await import('../server');

        await startServer();

        const sigtermHandler = signalHandlers.get('SIGTERM');
        expect(sigtermHandler).toBeDefined();

        try {
            sigtermHandler!();
            await new Promise(resolve => setTimeout(resolve, 10));
        } catch (error: any) {
            expect(error.message).toContain('process.exit(0)');
        }

        expect(mockClose).toHaveBeenCalled();
    });

    it('should handle uncaughtException and exit with code 1', async () => {
        const { AppLogger } = await import('../config/logger');
        const { startServer } = await import('../server');

        await startServer();

        const uncaughtHandler = signalHandlers.get('uncaughtException');
        expect(uncaughtHandler).toBeDefined();

        const testError = new Error('Test uncaught exception');

        try {
            uncaughtHandler!(testError);
        } catch (error: any) {
            expect(error.message).toContain('process.exit(1)');
        }

        expect(AppLogger.error).toHaveBeenCalledWith(
            'UNCAUGHT EXCEPTION! 💥 Shutting down...',
            expect.objectContaining({
                error: expect.stringContaining('Test uncaught exception'),
            })
        );
    });

    it('should handle unhandledRejection and exit with code 1', async () => {
        const { AppLogger } = await import('../config/logger');
        const { startServer } = await import('../server');

        await startServer();

        const unhandledHandler = signalHandlers.get('unhandledRejection');
        expect(unhandledHandler).toBeDefined();

        const testReason = 'Test unhandled rejection';

        try {
            unhandledHandler!(Promise.resolve(), testReason);
        } catch (error: any) {
            expect(error.message).toContain('process.exit(1)');
        }

        expect(AppLogger.error).toHaveBeenCalledWith(
            'UNHANDLED REJECTION! 💥 Shutting down...',
            expect.objectContaining({
                error: testReason,
            })
        );
    });

    it('should handle error during server initialization', async () => {
        const { AppLogger } = await import('../config/logger');
        const { initializeApp } = await import('../app');

        // Mock initializeApp to throw error
        (initializeApp as jest.Mock).mockRejectedValueOnce(new Error('Init failed'));

        const { startServer } = await import('../server');

        try {
            await startServer();
        } catch (error: any) {
            expect(error.message).toContain('process.exit(1)');
        }

        expect(AppLogger.error).toHaveBeenCalledWith(
            '❌ Fatal error starting server:',
            expect.objectContaining({
                error: expect.stringContaining('Init failed'),
            })
        );
    });

    it('should use PORT from environment if available', async () => {
        const originalPort = process.env.PORT;
        process.env.PORT = '5000';

        jest.resetModules();
        const { startServer } = await import('../server');

        await startServer();

        expect(mockListen).toHaveBeenCalledWith(5000, expect.any(Function));

        process.env.PORT = originalPort;
    });

    it('should log server startup information', async () => {
        const { AppLogger } = await import('../config/logger');
        const { startServer } = await import('../server');

        await startServer();

        expect(AppLogger.info).toHaveBeenCalledWith(expect.stringContaining('🚀 Server running on port'));
        expect(AppLogger.info).toHaveBeenCalledWith(expect.stringContaining('📱 Frontend URLs:'));
        expect(AppLogger.info).toHaveBeenCalledWith(expect.stringContaining('🏗️ Environment:'));
        expect(AppLogger.info).toHaveBeenCalledWith('✅ Server ready to receive requests');
    });
});

/**
 * Tests adicionales para config/prisma.ts
 * Cubriendo disconnect con error, máximo de reintentos, getDatabaseInfo con error
 * @jest-environment node
 */

// Mocks deben declararse antes de los imports
const mockAppLogger = {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
};

jest.mock('../logger', () => ({
    AppLogger: mockAppLogger,
}));

jest.mock('../database', () => ({
    databaseConfig: {
        getApplicationUrl: () => 'postgresql://test:test@localhost:5432/testdb',
        getConfig: () => ({
            database: 'testdb',
            host: 'localhost',
            enableLogging: true,
            enableQueryLogging: true,
        }),
    },
}));

describe('config/prisma additional coverage', () => {
    beforeEach(() => {
        jest.resetModules();
        jest.clearAllMocks();
    });

    it('disconnect does nothing if not connected', async () => {
        // Fresh import para tener isConnected = false
        let connectCalled = false;

        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { connectCalled = true; });
                $disconnect = jest.fn(async () => { });
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');

        // Intentar disconnect sin haber conectado - no debe hacer nada
        await prismaService.disconnect();

        // No se debió loguear desconexión porque no estaba conectado
        expect(mockAppLogger.info).not.toHaveBeenCalledWith(
            expect.stringContaining('Desconectado de base de datos')
        );
    });

    it('disconnect throws and logs error on failure', async () => {
        const disconnectError = new Error('Disconnect failed');
        let disconnectCalled = false;

        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { });
                $disconnect = jest.fn(async () => {
                    disconnectCalled = true;
                    throw disconnectError;
                });
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn();
            },
        }));

        // Reset mocks del logger antes de este test
        mockAppLogger.error.mockClear();

        const { prismaService } = await import('../prisma');

        // Conectar primero (esto debe funcionar)
        await prismaService.connect();

        // Ahora disconnect debe fallar
        try {
            await prismaService.disconnect();
        } catch (error) {
            // Esperamos que lance error
            expect((error as Error).message).toBe('Disconnect failed');
        }

        expect(disconnectCalled).toBe(true);
    });

    it('connect fails after max retries', async () => {
        let attempts = 0;

        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => {
                    attempts++;
                    throw new Error('Connection refused');
                });
                $disconnect = jest.fn();
                $queryRaw = jest.fn();
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');

        await expect(prismaService.connect()).rejects.toThrow('No se pudo conectar');
        expect(attempts).toBe(3); // maxRetries = 3
        expect(mockAppLogger.error).toHaveBeenCalledWith(
            expect.stringContaining('después de todos los intentos'),
            expect.any(Object)
        );
    });

    it('getClient logs debug when not connected', async () => {
        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn();
                $disconnect = jest.fn();
                $queryRaw = jest.fn();
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');

        // Llamar getClient sin conectar
        const client = prismaService.getClient();
        expect(client).toBeDefined();
        expect(mockAppLogger.debug).toHaveBeenCalledWith(
            expect.stringContaining('conexión en progreso')
        );
    });

    it('getDatabaseInfo throws and logs error on failure', async () => {
        const queryError = new Error('Query failed');

        let queryCallCount = 0;

        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { });
                $disconnect = jest.fn();
                // Primera llamada es para verificar conexión en connect(), segunda para getDatabaseInfo
                $queryRaw = jest.fn(async () => {
                    queryCallCount++;
                    if (queryCallCount > 1) {
                        throw queryError;
                    }
                    return [{ ok: 1 }];
                });
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');
        await prismaService.connect();

        await expect(prismaService.getDatabaseInfo()).rejects.toThrow('Query failed');
        expect(mockAppLogger.error).toHaveBeenCalledWith(
            expect.stringContaining('Error obteniendo información'),
            expect.any(Error)
        );
    });

    it('getConnectionStats returns correct stats', async () => {
        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { });
                $disconnect = jest.fn();
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');
        await prismaService.connect();

        const stats = prismaService.getConnectionStats();
        expect(stats).toMatchObject({
            isConnected: true,
            maxRetries: 3,
            database: 'testdb',
            host: 'localhost',
        });
    });

    it('executeTransaction fails after max retries', async () => {
        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { });
                $disconnect = jest.fn();
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn(async () => { throw new Error('Transaction failed'); });
            },
        }));

        const { prismaService } = await import('../prisma');
        await prismaService.connect();

        await expect(
            prismaService.executeTransaction(async () => 'test', 2)
        ).rejects.toThrow('Transaction failed');

        expect(mockAppLogger.error).toHaveBeenCalledWith(
            expect.stringContaining('Transacción falló después de todos los intentos'),
            expect.any(Object)
        );
    });

    it('cleanup calls disconnect', async () => {
        const disconnectMock = jest.fn(async () => { });

        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { });
                $disconnect = disconnectMock;
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');
        await prismaService.connect();

        await prismaService.cleanup();

        expect(mockAppLogger.info).toHaveBeenCalledWith(
            expect.stringContaining('Limpiando conexiones')
        );
    });

    it('connect with enableLogging true logs setup info', async () => {
        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { });
                $disconnect = jest.fn();
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');
        await prismaService.connect();

        // Con enableLogging: true, debe loguear info de setup
        expect(mockAppLogger.info).toHaveBeenCalledWith(
            expect.stringContaining('Prisma configurado'),
            expect.objectContaining({ database: 'testdb' })
        );
    });

    it('second connect call is a no-op', async () => {
        let connectCount = 0;

        jest.doMock('@prisma/client', () => ({
            PrismaClient: class MockPrismaClient {
                $connect = jest.fn(async () => { connectCount++; });
                $disconnect = jest.fn();
                $queryRaw = jest.fn(async () => [{ ok: 1 }]);
                $transaction = jest.fn();
            },
        }));

        const { prismaService } = await import('../prisma');

        await prismaService.connect();
        await prismaService.connect(); // Segunda llamada

        // Solo debe haberse conectado una vez
        expect(connectCount).toBe(1);
    });
});

import { Request, Response } from 'express';
import { PlatformAuthController, platformAuthValidation } from '../platformAuth.controller';
import { PlatformAuthService } from '../../services/platformAuth.service';
import { validationResult } from 'express-validator';

// Mock dependencies
jest.mock('../../services/platformAuth.service', () => ({
    PlatformAuthService: {
        login: jest.fn(),
        register: jest.fn(),
        updatePlatformUser: jest.fn(),
        deletePlatformUser: jest.fn(),
        registerClientWithTempPassword: jest.fn(),
        registerDadorWithTempPassword: jest.fn(),
        registerTransportistaWithTempPassword: jest.fn(),
        registerChoferWithTempPassword: jest.fn(),
        getUserProfile: jest.fn(),
        updatePassword: jest.fn(),
    }
}));

jest.mock('express-validator', () => ({
    validationResult: jest.fn(),
    body: jest.fn(() => {
        const chain: any = {};
        chain.isEmail = jest.fn().mockReturnValue(chain);
        chain.normalizeEmail = jest.fn().mockReturnValue(chain);
        chain.withMessage = jest.fn().mockReturnValue(chain);
        chain.isLength = jest.fn().mockReturnValue(chain);
        chain.matches = jest.fn().mockReturnValue(chain);
        chain.optional = jest.fn().mockReturnValue(chain);
        chain.customSanitizer = jest.fn((sanitizer: any) => {
            try {
                if (typeof sanitizer === 'function') {
                    sanitizer('test'); // Cubre rama string
                    sanitizer(123);    // Cubre rama no-string
                }
            } catch (e) { }
            return chain;
        });
        chain.isIn = jest.fn().mockReturnValue(chain);
        chain.isInt = jest.fn().mockReturnValue(chain);
        chain.notEmpty = jest.fn().mockReturnValue(chain);
        return chain;
    }),
}));
jest.mock('../../config/logger', () => ({
    AppLogger: {
        info: jest.fn(),
        error: jest.fn(),
    },
}));

describe('PlatformAuthController', () => {
    let req: Partial<Request>;
    let res: Partial<Response>;
    let jsonMock: jest.Mock;
    let statusMock: jest.Mock;
    let cookieMock: jest.Mock;
    let clearCookieMock: jest.Mock;

    // Helper para simular errores de validación
    const mockValidationErrors = (isEmpty: boolean) => {
        (validationResult as unknown as jest.Mock).mockReturnValue({
            isEmpty: () => isEmpty,
            array: () => isEmpty ? [] : [{ msg: 'Invalid field' }],
        });
    };

    beforeEach(() => {
        jest.clearAllMocks();

        jsonMock = jest.fn();
        statusMock = jest.fn().mockReturnValue({ json: jsonMock });
        cookieMock = jest.fn();
        clearCookieMock = jest.fn();

        res = {
            status: statusMock,
            json: jsonMock,
            cookie: cookieMock,
            clearCookie: clearCookieMock,
        } as unknown as Response;

        // Default: no validation errors
        mockValidationErrors(true);
    });

    describe('Validation Objects', () => {
        it('should define validation rules', () => {
            expect(platformAuthValidation.login).toBeDefined();
            expect(platformAuthValidation.register).toBeDefined();
            expect(platformAuthValidation.changePassword).toBeDefined();
            expect(platformAuthValidation.updateUser).toBeDefined();
        });
    });

    describe('login', () => {
        it('handles validation errors', async () => {
            mockValidationErrors(false);
            await PlatformAuthController.login(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(400);
        });

        it('logs in successfully', async () => {
            req = { body: { email: 'test@test.com', password: 'pass' }, ip: '127.0.0.1', get: jest.fn() } as any;
            (PlatformAuthService.login as jest.Mock).mockResolvedValue({
                success: true,
                token: 'tok',
                platformUser: { id: 1 }
            });

            await PlatformAuthController.login(req as Request, res as Response);

            expect(cookieMock).toHaveBeenCalledWith('platformToken', 'tok', expect.any(Object));
            expect(statusMock).toHaveBeenCalledWith(200);
        });

        it('handles invalid credentials', async () => {
            req = { body: { email: 'bad', password: 'bad' }, get: jest.fn() } as any;
            (PlatformAuthService.login as jest.Mock).mockResolvedValue({ success: false, message: 'Bad creds' });

            await PlatformAuthController.login(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(401);
        });

        it('handles server errors', async () => {
            req = { body: {}, get: jest.fn() } as any;
            (PlatformAuthService.login as jest.Mock).mockRejectedValue(new Error('Fail'));
            await PlatformAuthController.login(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(500);
        });
    });

    describe('updateUser', () => {
        it('updates user successfully', async () => {
            req = {
                user: { userId: 1 },
                params: { id: '2' },
                body: { nombre: 'New' }
            } as any;
            (PlatformAuthService.updatePlatformUser as jest.Mock).mockResolvedValue({ id: 2 });

            await PlatformAuthController.updateUser(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(200);
        });

        it('returns 401 if unauthenticated', async () => {
            req = { user: undefined } as any;
            await PlatformAuthController.updateUser(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(401);
        });
    });

    describe('deleteUser', () => {
        it('deletes user successfully', async () => {
            req = { user: { userId: 1 }, params: { id: '2' } } as any;
            (PlatformAuthService.deletePlatformUser as jest.Mock).mockResolvedValue(true);
            await PlatformAuthController.deleteUser(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(200);
        });

        it('returns 401 if unauthenticated', async () => {
            req = { user: undefined } as any;
            await PlatformAuthController.deleteUser(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(401);
        });
    });

    describe('register', () => {
        it('registers successfully', async () => {
            req = { body: {}, user: { userId: 1 }, ip: '1.2.3.4' } as any;
            (PlatformAuthService.register as jest.Mock).mockResolvedValue({ success: true, platformUser: {} });
            await PlatformAuthController.register(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(201);
        });

        it('returns 401 if unauthenticated', async () => {
            req = { user: undefined } as any;
            await PlatformAuthController.register(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(401);
        });

        it('handles service errors', async () => {
            req = { body: {}, user: { userId: 1 } } as any;
            (PlatformAuthService.register as jest.Mock).mockResolvedValue({ success: false, message: 'Exists' });
            await PlatformAuthController.register(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(400);
        });

        it('handles unexpected errors', async () => {
            req = { body: {}, user: { userId: 1 } } as any;
            (PlatformAuthService.register as jest.Mock).mockRejectedValue(new Error('Fail'));
            await PlatformAuthController.register(req as Request, res as Response);
            expect(statusMock).toHaveBeenCalledWith(400);
        });
    });

    describe('Wizards', () => {
        describe('Wizards', () => {
            const wizards = [
                { name: 'registerClientWizard', method: 'registerClientWithTempPassword', body: { clienteId: 10 }, data: { clienteId: 10, empresaId: null } },
                { name: 'registerDadorWizard', method: 'registerDadorWithTempPassword', body: { dadorCargaId: 10 }, data: { dadorCargaId: 10, empresaId: null } },
                { name: 'registerTransportistaWizard', method: 'registerTransportistaWithTempPassword', body: { empresaTransportistaId: 10 }, data: { empresaTransportistaId: 10, empresaId: null } },
                { name: 'registerChoferWizard', method: 'registerChoferWithTempPassword', body: { choferId: 10 }, data: { choferId: 10, empresaId: null } },
            ];

            wizards.forEach((wizard) => {
                describe(wizard.name, () => {
                    const controllerMethod = (PlatformAuthController as any)[wizard.name];
                    const serviceMethod = (PlatformAuthService as any)[wizard.method];

                    it('success', async () => {
                        req = { user: { userId: 1 }, body: wizard.body } as any;
                        serviceMethod.mockResolvedValue({ success: true, platformUser: {}, tempPassword: '123' });
                        await controllerMethod(req as Request, res as Response);
                        expect(statusMock).toHaveBeenCalledWith(201);
                    });

                    it('success with empresaId', async () => {
                        req = { user: { userId: 1 }, body: { ...wizard.body, empresaId: 5 } } as any;
                        serviceMethod.mockResolvedValue({ success: true });
                        await controllerMethod(req as Request, res as Response);
                        expect(serviceMethod).toHaveBeenCalledWith(
                            expect.objectContaining({ ...wizard.data, empresaId: 5 }),
                            expect.anything()
                        );
                        expect(statusMock).toHaveBeenCalledWith(201);
                    });

                    it('handles validation errors', async () => {
                        mockValidationErrors(false);
                        await controllerMethod(req as Request, res as Response);
                        expect(statusMock).toHaveBeenCalledWith(400);
                    });

                    it('returns 401 if unauthenticated', async () => {
                        req = { user: undefined } as any;
                        await controllerMethod(req as Request, res as Response);
                        expect(statusMock).toHaveBeenCalledWith(401);
                    });

                    it('handles service failure', async () => {
                        req = { user: { userId: 1 }, body: wizard.body } as any;
                        serviceMethod.mockResolvedValue({ success: false, message: 'Fail' });
                        await controllerMethod(req as Request, res as Response);
                        expect(statusMock).toHaveBeenCalledWith(400);
                    });

                    it('handles exceptions', async () => {
                        req = { user: { userId: 1 }, body: wizard.body } as any;
                        serviceMethod.mockRejectedValue(new Error('Crash'));
                        await controllerMethod(req as Request, res as Response);
                        expect(statusMock).toHaveBeenCalledWith(500);
                    });
                });
            });
        });

        // Agregar validación errors a otros métodos
        describe('updateUser errors', () => {
            it('handles validation errors', async () => {
                mockValidationErrors(false);
                await PlatformAuthController.updateUser(req as Request, res as Response);
                expect(statusMock).toHaveBeenCalledWith(400);
            });
            it('handles exceptions', async () => {
                req = { user: { userId: 1 }, params: { id: 1 } } as any;
                (PlatformAuthService.updatePlatformUser as jest.Mock).mockRejectedValue(new Error('Fail'));
                await PlatformAuthController.updateUser(req as Request, res as Response);
                expect(statusMock).toHaveBeenCalledWith(500);
            });
        });

        describe('deleteUser errors', () => {
            it('handles exceptions', async () => {
                req = { user: { userId: 1 }, params: { id: 1 } } as any;
                (PlatformAuthService.deletePlatformUser as jest.Mock).mockRejectedValue(new Error('Fail'));
                await PlatformAuthController.deleteUser(req as Request, res as Response);
                expect(statusMock).toHaveBeenCalledWith(500);
            });
        });

        describe('register errors', () => {
            it('handles validation errors', async () => {
