    describe('identifyUser', () => {
        it('should find user by identifier type and value', async () => {
            const mockUser = {
                id: 1,
                identifierType: 'EMAIL',
                identifier_value: 'test@example.com',
                nombre: 'Test',
                apellido: 'User',
                empresaId: 100,
